import { useState, useEffect, useRef } from 'react';
import {
  FiUpload,
  FiImage,
  FiTrash2,
  FiChevronLeft,
  FiChevronRight,
  FiX,
  FiLink,
} from 'react-icons/fi';

import {
  getMyProducts,
  createProduct,
  updateProduct,
  deleteProduct,
} from '../services/api';

import { useAuth } from '../context/AuthContext';
import { toast } from 'react-toastify';

const EMPTY_FORM = {
  name: '',
  description: '',
  price: '',
  discountPrice: '',
  category: '',
  stock: '',
  brand: '',
  images: [],
};

const SellerDashboard = () => {
  const [products, setProducts] = useState([]);
  const [tab, setTab] = useState('products');
  const [form, setForm] = useState(EMPTY_FORM);
  const [editId, setEditId] = useState(null);
  const [previews, setPreviews] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [dragging, setDragging] = useState(false);
  const [urlInput, setUrlInput] = useState('');
  const [showUrl, setShowUrl] = useState(false);

  const fileInputRef = useRef(null);

  const { user } = useAuth();

  const BACKEND_URL = 'http://localhost:5000';

  // ─────────────────────────────────────────────────────────────
  // IMAGE URL HELPER
  // ─────────────────────────────────────────────────────────────

  const getImageUrl = (image) => {
    if (!image) return null;

    if (
      typeof image === 'string' &&
      (image.startsWith('http') ||
        image.startsWith('data:'))
    ) {
      return image;
    }

    if (typeof image === 'string') {
      const cleanPath = image.replace(/^\/+/, '');

      return `${BACKEND_URL}/${cleanPath}`;
    }

    return null;
  };

  // ─────────────────────────────────────────────────────────────
  // LOAD PRODUCTS
  // ─────────────────────────────────────────────────────────────

  const load = () => {
    getMyProducts().then((r) =>
      setProducts(r.data.products)
    );
  };

  useEffect(() => {
    load();
  }, []);

  // ─────────────────────────────────────────────────────────────
  // PROCESS FILES
  // ─────────────────────────────────────────────────────────────

  const processFiles = (files) => {
    const imageFiles = Array.from(files).filter(
      (f) => f.type.startsWith('image/')
    );

    if (!imageFiles.length) return;

    imageFiles.forEach((file) => {
      if (file.size > 5 * 1024 * 1024) {
        toast.error(
          `${file.name} is too large. Max 5MB allowed`
        );
        return;
      }

      const reader = new FileReader();

      reader.onload = (e) => {
        const url = e.target.result;

        setPreviews((prev) => [
          ...prev,
          { file, url },
        ]);

        setForm((prev) => ({
          ...prev,
          images: [...prev.images, url],
        }));
      };

      reader.readAsDataURL(file);
    });
  };

  const onFileInput = (e) => {
    processFiles(e.target.files);
    e.target.value = '';
  };

  const onDrop = (e) => {
    e.preventDefault();

    setDragging(false);

    processFiles(e.dataTransfer.files);
  };

  // ─────────────────────────────────────────────────────────────
  // IMAGE URL ADD
  // ─────────────────────────────────────────────────────────────

  const addImageUrl = () => {
    const url = urlInput.trim();

    if (!url) return;

    if (!url.startsWith('http')) {
      toast.error('Please enter valid image URL');
      return;
    }

    if (form.images.includes(url)) {
      toast.error('Image already exists');
      return;
    }

    setForm((prev) => ({
      ...prev,
      images: [...prev.images, url],
    }));

    setUrlInput('');
    setShowUrl(false);
  };

  // ─────────────────────────────────────────────────────────────
  // REMOVE IMAGE
  // ─────────────────────────────────────────────────────────────

  const removeImage = (index) => {
    setForm((prev) => ({
      ...prev,
      images: prev.images.filter(
        (_, i) => i !== index
      ),
    }));

    setPreviews((prev) =>
      prev.filter((_, i) => i !== index)
    );
  };

  // ─────────────────────────────────────────────────────────────
  // MOVE IMAGE
  // ─────────────────────────────────────────────────────────────

  const moveImage = (index, dir) => {
    const to = index + dir;

    if (to < 0 || to >= form.images.length) return;

    const imgs = [...form.images];

    [imgs[index], imgs[to]] = [
      imgs[to],
      imgs[index],
    ];

    setForm((prev) => ({
      ...prev,
      images: imgs,
    }));
  };

  // ─────────────────────────────────────────────────────────────
  // SUBMIT
  // ─────────────────────────────────────────────────────────────

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (form.images.length === 0) {
      toast.error(
        'Please add at least one image'
      );
      return;
    }

    setUploading(true);

    try {
      const payload = {
        ...form,
        price: Number(form.price),
        discountPrice: form.discountPrice
          ? Number(form.discountPrice)
          : undefined,
        stock: Number(form.stock),
        images: form.images,
      };

      if (editId) {
        await updateProduct(editId, payload);
        toast.success('Product updated!');
      } else {
        await createProduct(payload);
        toast.success(
          'Product submitted for approval!'
        );
      }

      resetForm();
      setTab('products');
      load();
    } catch (err) {
      toast.error(
        err.response?.data?.message ||
          'Something went wrong'
      );
    } finally {
      setUploading(false);
    }
  };

  // ─────────────────────────────────────────────────────────────
  // RESET
  // ─────────────────────────────────────────────────────────────

  const resetForm = () => {
    setForm(EMPTY_FORM);
    setPreviews([]);
    setEditId(null);
    setUrlInput('');
    setShowUrl(false);
  };

  // ─────────────────────────────────────────────────────────────
  // EDIT
  // ─────────────────────────────────────────────────────────────

  const handleEdit = (p) => {
    setForm({
      name: p.name,
      description: p.description,
      price: p.price,
      discountPrice: p.discountPrice || '',
      category: p.category,
      stock: p.stock,
      brand: p.brand || '',
      images: p.images || [],
    });

    setPreviews([]);

    setEditId(p._id);

    setTab('add');
  };

  // ─────────────────────────────────────────────────────────────
  // DELETE
  // ─────────────────────────────────────────────────────────────

  const handleDelete = async (id) => {
    if (window.confirm('Delete this product?')) {
      await deleteProduct(id);

      load();

      toast.success('Product deleted');
    }
  };

  // ─────────────────────────────────────────────────────────────
  // UI
  // ─────────────────────────────────────────────────────────────

  return (
    <div className="admin-page">
      <h1>Seller Dashboard</h1>

      <div className="admin-tabs">
        <button
          className={
            tab === 'products' ? 'active' : ''
          }
          onClick={() => setTab('products')}
        >
          My Products
        </button>

        <button
          className={
            tab === 'add' ? 'active' : ''
          }
          onClick={() => {
            resetForm();
            setTab('add');
          }}
        >
          + Add Product
        </button>
      </div>

      {/* PRODUCTS */}

      {tab === 'products' && (
        <table className="admin-table">
          <thead>
            <tr>
              <th>Image</th>
              <th>Name</th>
              <th>Price</th>
              <th>Stock</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>

          <tbody>
            {products.map((p) => (
              <tr key={p._id}>
                <td>
                  {p.images?.[0] ? (
                    <img
                      src={getImageUrl(
                        p.images[0]
                      )}
                      alt={p.name}
                      style={{
                        width: 48,
                        height: 60,
                        objectFit: 'cover',
                        borderRadius: 4,
                      }}
                    />
                  ) : (
                    <div
                      style={{
                        width: 48,
                        height: 60,
                        background: '#f5f0e8',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        borderRadius: 4,
                        color: '#777',
                        fontSize: 20,
                      }}
                    >
                      <FiImage />
                    </div>
                  )}
                </td>

                <td>{p.name}</td>

                <td>PKR {p.price}</td>

                <td>{p.stock}</td>

                <td>
                  <span
                    className={
                      p.isApproved
                        ? 'badge-green'
                        : 'badge-yellow'
                    }
                  >
                    {p.isApproved
                      ? 'Approved'
                      : 'Pending'}
                  </span>
                </td>

                <td>
                  <button
                    className="btn-sm"
                    onClick={() =>
                      handleEdit(p)
                    }
                  >
                    Edit
                  </button>

                  <button
                    className="btn-sm btn-danger"
                    onClick={() =>
                      handleDelete(p._id)
                    }
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {/* FORM */}

      {tab === 'add' && (
        <form
          className="product-form"
          onSubmit={handleSubmit}
        >
          <h2>
            {editId
              ? 'Edit Product'
              : 'Add New Product'}
          </h2>

          {['name', 'brand', 'category'].map(
            (f) => (
              <input
                key={f}
                placeholder={
                  f.charAt(0).toUpperCase() +
                  f.slice(1)
                }
                value={form[f]}
                onChange={(e) =>
                  setForm((p) => ({
                    ...p,
                    [f]: e.target.value,
                  }))
                }
                required={f !== 'brand'}
              />
            )
          )}

          <textarea
            placeholder="Description"
            value={form.description}
            onChange={(e) =>
              setForm((p) => ({
                ...p,
                description: e.target.value,
              }))
            }
            required
            rows={3}
          />

          <div className="form-row">
            <input
              type="number"
              placeholder="Price"
              value={form.price}
              onChange={(e) =>
                setForm((p) => ({
                  ...p,
                  price: e.target.value,
                }))
              }
              required
            />

            <input
              type="number"
              placeholder="Discount Price"
              value={form.discountPrice}
              onChange={(e) =>
                setForm((p) => ({
                  ...p,
                  discountPrice:
                    e.target.value,
                }))
              }
            />

            <input
              type="number"
              placeholder="Stock"
              value={form.stock}
              onChange={(e) =>
                setForm((p) => ({
                  ...p,
                  stock: e.target.value,
                }))
              }
              required
            />
          </div>

          {/* IMAGE SECTION */}

          <div style={{ marginTop: '1rem' }}>
            <label
              style={{
                display: 'block',
                fontWeight: 600,
                marginBottom: '0.6rem',
              }}
            >
              Product Images
            </label>

            <div
              onDragEnter={(e) => {
                e.preventDefault();
                setDragging(true);
              }}
              onDragOver={(e) => {
                e.preventDefault();
                setDragging(true);
              }}
              onDragLeave={(e) => {
                e.preventDefault();
                setDragging(false);
              }}
              onDrop={onDrop}
              onClick={() =>
                fileInputRef.current?.click()
              }
              style={{
                border: `2px dashed ${
                  dragging
                    ? '#c47878'
                    : '#e4cfa0'
                }`,
                borderRadius: 8,
                padding: '1.5rem',
                textAlign: 'center',
                cursor: 'pointer',
                background: dragging
                  ? '#fff5f5'
                  : '#fdfaf4',
              }}
            >
              <input
                ref={fileInputRef}
                type="file"
                multiple
                accept="image/*"
                style={{ display: 'none' }}
                onChange={onFileInput}
              />

              <div
                style={{
                  fontSize: '2.2rem',
                  marginBottom: '0.75rem',
                  color: dragging
                    ? '#c47878'
                    : '#2a2424',
                  display: 'flex',
                  justifyContent: 'center',
                }}
              >
                {dragging ? (
                  <FiUpload />
                ) : (
                  <FiImage />
                )}
              </div>

              <p
                style={{
                  margin: 0,
                  fontWeight: 600,
                }}
              >
                Drag & Drop Images Here
              </p>

              <button
                type="button"
                style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: 6,
                  marginTop: '1rem',
                  padding:
                    '0.55rem 1.25rem',
                  background: '#2a2424',
                  color: '#fff',
                  border: 'none',
                  borderRadius: 6,
                  pointerEvents: 'none',
                }}
              >
                <FiUpload />
                Attach Files
              </button>
            </div>

            {/* URL */}

            {!showUrl ? (
              <button
                type="button"
                onClick={() =>
                  setShowUrl(true)
                }
                style={{
                  marginTop: '0.75rem',
                  background: 'none',
                  border: 'none',
                  color: '#777',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  gap: 5,
                }}
              >
                <FiLink />
                Add image by URL
              </button>
            ) : (
              <div
                style={{
                  display: 'flex',
                  gap: 8,
                  marginTop: '0.75rem',
                }}
              >
                <input
                  type="url"
                  value={urlInput}
                  onChange={(e) =>
                    setUrlInput(
                      e.target.value
                    )
                  }
                  placeholder="https://example.com/image.jpg"
                  style={{ flex: 1 }}
                />

                <button
                  type="button"
                  className="btn-sm"
                  onClick={addImageUrl}
                >
                  Add
                </button>

                <button
                  type="button"
                  className="btn-sm"
                  onClick={() => {
                    setShowUrl(false);
                    setUrlInput('');
                  }}
                >
                  <FiX />
                </button>
              </div>
            )}

            {/* PREVIEWS */}

            {form.images.length > 0 && (
              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns:
                    'repeat(auto-fill, minmax(90px, 1fr))',
                  gap: 10,
                  marginTop: '1rem',
                }}
              >
                {form.images.map((url, i) => (
                  <div
                    key={i}
                    style={{
                      position: 'relative',
                      borderRadius: 8,
                      overflow: 'hidden',
                      border:
                        i === 0
                          ? '2px solid #d4a840'
                          : '1px solid #ddd',
                    }}
                  >
                    <img
                      src={getImageUrl(url)}
                      alt=""
                      style={{
                        width: '100%',
                        aspectRatio: '3/4',
                        objectFit: 'cover',
                      }}
                    />

                    <div
                      style={{
                        position: 'absolute',
                        inset: 0,
                        background:
                          'rgba(0,0,0,0.45)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent:
                          'center',
                        gap: 6,
                      }}
                    >
                      {i > 0 && (
                        <button
                          type="button"
                          onClick={() =>
                            moveImage(i, -1)
                          }
                          style={iconBtnStyle}
                        >
                          <FiChevronLeft />
                        </button>
                      )}

                      <button
                        type="button"
                        onClick={() =>
                          removeImage(i)
                        }
                        style={{
                          ...iconBtnStyle,
                          background:
                            'rgba(220,38,38,0.8)',
                        }}
                      >
                        <FiTrash2 size={14} />
                      </button>

                      {i <
                        form.images.length -
                          1 && (
                        <button
                          type="button"
                          onClick={() =>
                            moveImage(i, 1)
                          }
                          style={iconBtnStyle}
                        >
                          <FiChevronRight />
                        </button>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* ACTIONS */}

          <div
            style={{
              display: 'flex',
              gap: 10,
              marginTop: '1.5rem',
            }}
          >
            <button
              className="btn-primary"
              type="submit"
              disabled={
                uploading ||
                form.images.length === 0
              }
            >
              {uploading
                ? 'Submitting...'
                : editId
                ? 'Update Product'
                : 'Submit Product'}
            </button>

            <button
              className="btn-ghost"
              type="button"
              onClick={() => {
                resetForm();
                setTab('products');
              }}
            >
              Cancel
            </button>
          </div>
        </form>
      )}
    </div>
  );
};

export default SellerDashboard;

// ─────────────────────────────────────────────────────────────
// ICON BUTTON STYLE
// ─────────────────────────────────────────────────────────────

const iconBtnStyle = {
  width: 30,
  height: 30,
  borderRadius: '50%',
  border: 'none',
  background: 'rgba(255,255,255,0.18)',
  backdropFilter: 'blur(6px)',
  color: '#fff',
  fontSize: '0.9rem',
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  transition: 'all 0.2s ease',
};
